	mainArrow.BackgroundTransparency = 1
	mainArrow.Text = "Ō¢╝"
	mainArrow.TextColor3 = WHITE
	mainArrow.TextSize = 14
	mainArrow.Font = Enum.Font.Code
	mainArrow.TextXAlignment = Enum.TextXAlignment.Center
