	local function closeDropdown()
		isOpen = false
		panel.Visible = false
		mainLabel.Visible = true
		mainArrow.Visible = true
		if multiSelect then
			updateMainLabel()
		end
	end

	dropdown.MouseButton1Click:Connect(function()
		if isOpen then
			closeDropdown()
		else
			openDropdown()
		end
