local function createTooltip(name, text, parent)
	local frame = Instance.new("Frame")
	frame.Name = name
	frame.BackgroundColor3 = Color3.fromRGB(16, 16, 16)
	frame.BorderSizePixel = 0
	frame.ZIndex = 100
