local minimizedSize = UDim2.new(0, 170, 0, 20)

MainMinimize.MouseButton1Click:Connect(function()
	isMinimized = not isMinimized
	local rows = getRows()

	if isMinimized then
		MainGroup.Size = minimizedSize
		for _, row in ipairs(rows) do
			row.Visible = false
		end
		MainMinimize.Text = "+"
	else
