local PLACE_ID = 12943245078
local HOLD_TIME = 1.0
local GREY = Color3.fromRGB(80, 80, 80)





LJoinXLButton.Text = ""

local fillBar = Instance.new("Frame")
fillBar.Name = "FillBar"
fillBar.Size = UDim2.new(0, 0, 1, 0)
fillBar.Position = UDim2.new(0, 0, 0, 0)
