	label.ZIndex = 101
	label.Parent = frame

	if parent then
		parent.MouseEnter:Connect(function()
			local abs = parent.AbsolutePosition
			local size = parent.AbsoluteSize
			frame.Position = UDim2.new(0, abs.X + size.X + 10, 0, abs.Y)
			frame.Visible = true
		end)

		parent.MouseLeave:Connect(function()
			frame.Visible = false
		end)
	end

	return frame
